                ))
                all_passed = False
                continue

            actual = results[check.location]
            passed, message = self._perform_check(actual, check)

            test_results.append(TestResult(
                check_name=check.name,
                passed=passed,
                actual_value=actual,
                expected_value=check.expected,
                message=message
            ))

            if not passed:
                all_passed = False

        return all_passed, test_results

